VALUES(1, 'Áo thun nam Active Dry cổ tròn', 'Áo thun nam chất liệu polyester co giãn 4 chiều, bề mặt vải thoáng khí, phù hợp tập luyện nhẹ và mặc hằng ngày. Form regular tôn dáng, dễ phối với jeans hoặc jogger. Đường may vai và nách gia cố để giữ form sau nhiều lần giặt máy. Tu khoa tim kiem: ao thun nam, the thao, thoang khi, dry fit, mac hang ngay.', 1, 1, true, '2026-03-26 14:52:35.367', '2026-03-26 14:52:35.367', 429000.00, 4.6, 184);
VALUES(2, 'Quần jeans nam straight fit xanh đậm', 'Quần jeans nam form straight fit, chất denim pha spandex tạo cảm giác thoải mái khi ngồi lâu hoặc di chuyển nhiều. Cạp chắc, đường may đũng gia cố, phù hợp đi làm và đi chơi cuối tuần. Màu xanh đậm dễ phối áo sơ mi, áo thun và áo khoác. Tu khoa tim kiem: quan jeans nam, straight fit, denim, di lam, pho do.', 14, 3, true, '2026-03-26 14:52:35.367', '2026-03-26 14:52:35.367', 899000.00, 4.5, 132);
VALUES(3, 'Giày thể thao nam RunFlex đế êm', 'Giày thể thao nam thiết kế ôm chân vừa phải, đế cao su bám sàn tốt trên bề mặt đô thị. Lót trong êm và thoáng khí, phù hợp đi bộ đường dài, tập nhẹ và sử dụng hằng ngày. Form hiện đại, phối tốt với quần jogger hoặc jeans. Tu khoa tim kiem: giay the thao nam, de em, di bo, runflex, sneaker.', 2, 5, true, '2026-03-26 14:52:35.367', '2026-03-26 14:52:35.367', 1299000.00, 4.7, 221);
VALUES(4, 'Áo khoác nữ gió nhẹ Urban Shell', 'Áo khoác nữ chất liệu nhẹ, cản gió cơ bản, phù hợp di chuyển buổi sáng và chiều tối. Form vừa vặn, dễ phối với váy hoặc quần jeans. Bề mặt ít nhăn và nhanh khô, tiện cho lịch trình bận rộn. Tu khoa tim kiem: ao khoac nu, can gio, di lam, urban, thoi trang nu.', 16, 12, true, '2026-03-26 14:52:35.367', '2026-03-26 14:52:35.367', 1199000.00, 4.4, 96);
VALUES(5, 'Váy nữ midi Linen Grace', 'Váy midi nữ chất liệu linen pha, bề mặt mềm và thoáng, phù hợp mặc cả ngày trong môi trường văn phòng hoặc dạo phố. Thiết kế tối giản, tôn dáng, dễ phối cùng blazer hoặc cardigan mỏng. Tu khoa tim kiem: vay midi, linen, nu tinh, di lam, smart casual.', 15, 10, true, '2026-03-26 14:52:35.367', '2026-03-26 14:52:35.367', 759000.00, 4.5, 113);
VALUES(6, 'Giày nữ Classic Heel 5cm', 'Giày nữ gót thấp 5cm, thiết kế thanh lịch cho môi trường công sở và sự kiện nhẹ. Phần lót mềm, giảm áp lực mũi chân khi di chuyển. Dáng giày dễ phối với chân váy, quần tây hoặc jeans ôm. Tu khoa tim kiem: giay nu, got thap, cong so, thanh lich, classic.', 13, 11, true, '2026-03-26 14:52:35.367', '2026-03-26 14:52:35.367', 1099000.00, 4.3, 78);
VALUES(7, 'Áo trẻ em cotton mềm SoftPlay', 'Áo trẻ em cotton mềm, thân thiện da nhạy cảm, thoáng và thấm hút tốt. Form vừa vặn, dễ cử động khi vui chơi và đi học. Họa tiết đơn giản, màu sắc tươi sáng phù hợp lứa tuổi từ 6 đến 12. Tu khoa tim kiem: ao tre em, cotton mem, an toan da, di hoc, be trai be gai.', 11, 13, true, '2026-03-26 14:52:35.367', '2026-03-26 14:52:35.367', 239000.00, 4.7, 165);
VALUES(8, 'Balo học sinh SmartPack 20L', 'Balo học sinh dung tích 20L, ngăn chính rộng và ngăn phụ khoa học. Quai đeo có đệm êm, phân bổ lực tốt cho vai, phù hợp học sinh cấp 2 và cấp 3. Chất liệu bền nhẹ, chống bám bụi cơ bản và dễ vệ sinh. Tu khoa tim kiem: balo hoc sinh, 20l, ngan chong soc, quai dem em, di hoc.', 10, 16, true, '2026-03-26 14:52:35.367', '2026-03-26 14:52:35.367', 529000.00, 4.6, 142);
VALUES(9, 'Mũ lưỡi trai unisex AirCap', 'Mũ lưỡi trai unisex form đứng, chất liệu nhẹ và thoáng, phù hợp hoạt động ngoài trời và đi lại hằng ngày. Phần khóa điều chỉnh linh hoạt, ôm đầu ổn định cho nhiều vòng đầu khác nhau. Tu khoa tim kiem: mu luoi trai, unisex, ngoai troi, streetwear, phu kien.', 17, 17, true, '2026-03-26 14:52:35.367', '2026-03-26 14:52:35.367', 329000.00, 4.4, 87);
VALUES(10, 'Túi đeo chéo urban mini', 'Túi đeo chéo mini phong cách đường phố, tối ưu cho vật dụng thiết yếu như điện thoại, ví và tai nghe. Thiết kế gọn, dây đeo điều chỉnh nhanh, chất liệu bền chống bám bụi nhẹ. Phù hợp đi chơi, dạo phố và du lịch ngắn ngày. Tu khoa tim kiem: tui deo cheo, urban, mini bag, streetwear, phu kien.', 18, 18, true, '2026-03-26 14:52:35.367', '2026-03-26 14:52:35.367', 459000.00, 4.5, 64);
VALUES(11, 'Áo thun nam Nike Core 1', 'Áo thun nam dòng Core của Nike, tối ưu cho nhu cầu mặc hằng ngày và di chuyển linh hoạt. Chất liệu chọn lọc, hoàn thiện chắc chắn, dễ phối theo nhiều phong cách từ basic đến streetwear. Tu khoa tim kiem: áo thun nam, nike, core, mac hang ngay, de pho do. Tu khoa tim kiem: áo thun nam, nike, core, de pho do, mac hang ngay.', 1, 1, true, '2026-03-26 14:52:35.367', '2026-03-26 14:52:35.367', 429000.00, 4.0, 40);
